const listHostsByEnvironmentID = `-- name: ListHostsByEnvironmentID :many
SELECT
    h.id, h.name, h.display_name, h.description, h.hostname, h.ip_address, h.os, h.arch, h.cpu_cores, h.memory_mb, h.disk_gb, h.labels, h.scope, h.workspace_id, h.namespace_id, h.environment_id, h.status, h.created_at, h.updated_at,
    e.name AS environment_name
FROM hosts h
LEFT JOIN environments e ON h.environment_id = e.id
WHERE h.environment_id = $1
    AND ($2::VARCHAR IS NULL OR h.status = $2)
    AND ($3::VARCHAR IS NULL
         OR h.name ILIKE '%' || $3 || '%'
         OR h.display_name ILIKE '%' || $3 || '%')
ORDER BY
    CASE WHEN $4::VARCHAR = 'name' AND $5::VARCHAR = 'asc' THEN h.name END ASC,
    CASE WHEN $4::VARCHAR = 'name' AND $5::VARCHAR = 'desc' THEN h.name END DESC,
    CASE WHEN $4::VARCHAR = 'created_at' AND $5::VARCHAR = 'asc' THEN h.created_at END ASC,
    CASE WHEN $4::VARCHAR = 'created_at' AND $5::VARCHAR = 'desc' THEN h.created_at END DESC,
    h.created_at DESC
LIMIT $7::INT
OFFSET $6::INT
`

